package org.eclipse.rdf4j.benchmark.common;

import static org.junit.jupiter.api.Assertions.assertTrue;
import static org.junit.jupiter.api.DynamicTest.dynamicTest;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Optional;
import java.util.OptionalLong;
import java.util.stream.IntStream;
import java.util.stream.Stream;

import org.apache.jena.datatypes.RDFDatatype;
import org.apache.jena.datatypes.TypeMapper;
import org.apache.jena.query.ARQ;
import org.apache.jena.query.Dataset;
import org.apache.jena.query.DatasetFactory;
import org.apache.jena.query.QueryExecution;
import org.apache.jena.query.QuerySolution;
import org.apache.jena.query.ReadWrite;
import org.apache.jena.query.ResultSet;
import org.apache.jena.rdf.model.AnonId;
import org.apache.jena.rdf.model.RDFNode;
import org.apache.jena.rdf.model.ResourceFactory;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator.Theme;
import org.eclipse.rdf4j.model.BNode;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.rio.helpers.AbstractRDFHandler;
import org.junit.jupiter.api.DynamicTest;
import org.junit.jupiter.api.TestFactory;

class ThemeQueryCatalogJenaOracleTest {

	private static final int FIRST_DISABLED_QUERY_INDEX = 11;
	private static final int SPARSE_FIRST_DISABLED_QUERY_INDEX = 2;

	@TestFactory
	Stream<DynamicTest> themeQueriesMatchJenaCountsAndCountBindings() {
		return Stream.of(Theme.values())
				.filter(ThemeQueryCatalogJenaOracleTest::matchesThemeFilter)
				.map(theme -> dynamicTest(theme.name(), () -> verifyThemeQueries(theme)));
	}

	private static void verifyThemeQueries(Theme theme) {
		Dataset dataset = jenaDatasetFor(theme);
		try {
			List<String> mismatches = new ArrayList<>();
			List<BenchmarkQuery> queries = ThemeQueryCatalog.benchmarkQueriesFor(theme);
			for (int index : queryIndexesFor(theme, queries)) {
				BenchmarkQuery query = queries.get(index);
				String label = label(theme, index, query);
				System.out.println("Jena oracle: " + label);
				dataset.begin(ReadWrite.READ);
				try {
					verifyQueryMatchesJena(theme, index, query, executeSelect(query, dataset), mismatches);
				} finally {
					dataset.end();
				}
			}
			assertTrue(mismatches.isEmpty(), () -> String.join(System.lineSeparator(), mismatches));
		} finally {
			dataset.close();
		}
	}

	private static void verifyQueryMatchesJena(Theme theme, int index, BenchmarkQuery query, JenaResult result,
			List<String> mismatches) {
		String label = label(theme, index, query);
		if (query.getExpectedCount() != result.rows()) {
			mismatches.add(label + " row count expected " + query.getExpectedCount() + " but was " + result.rows());
		}

		OptionalLong expectedCountBindingValue = ThemeQueryCatalog.expectedCountBindingValueFor(theme, index);
		if (expectedCountBindingValue.isPresent()) {
			if (result.rows() != 1) {
				mismatches.add(label + " aggregate row count expected 1 but was " + result.rows());
			}
			if (result.countValue().isEmpty()) {
				mismatches.add(label + " did not project ?count");
			} else if (expectedCountBindingValue.getAsLong() != result.countValue().getAsLong()) {
				mismatches.add(label + " ?count expected " + expectedCountBindingValue.getAsLong() + " but was "
						+ result.countValue().getAsLong());
			}
		}
	}

	private static String label(Theme theme, int index, BenchmarkQuery query) {
		return theme + " query " + index + " (" + query.getName() + ")";
	}

	private static JenaResult executeSelect(BenchmarkQuery query, Dataset dataset) {
		long rows = 0;
		OptionalLong countValue = OptionalLong.empty();
		try (QueryExecution queryExecution = QueryExecution.dataset(dataset)
				.query(query.getQuery())
				.set(ARQ.spillToDiskThreshold, 1024L)
				.build()) {
			ResultSet resultSet = queryExecution.execSelect();
			while (resultSet.hasNext()) {
				QuerySolution solution = resultSet.nextSolution();
				rows++;
				if (solution.contains("count")) {
					RDFNode countNode = solution.get("count");
					assertTrue(countNode.isLiteral(), query.getName() + " projected non-literal ?count: " + countNode);
					countValue = OptionalLong.of(countNode.asLiteral().getLong());
				}
			}
		}
		return new JenaResult(rows, countValue);
	}

	private static boolean matchesThemeFilter(Theme theme) {
		String filter = System.getProperty("rdf4j.jenaOracle.theme");
		return filter == null || filter.isBlank() || theme.name().equals(filter);
	}

	private static int[] queryIndexesFor(Theme theme, List<BenchmarkQuery> queries) {
		int enabledQueryCount = Math.min(firstDisabledQueryIndex(theme), queries.size());
		String filter = System.getProperty("rdf4j.jenaOracle.query");
		if (filter == null || filter.isBlank()) {
			return IntStream.range(0, enabledQueryCount).toArray();
		}
		return Arrays.stream(filter.split(","))
				.map(String::trim)
				.filter(value -> !value.isEmpty())
				.mapToInt(Integer::parseInt)
				.filter(index -> index >= 0 && index < queries.size())
				.toArray();
	}

	private static int firstDisabledQueryIndex(Theme theme) {
		if (theme == Theme.SPARSE) {
			return SPARSE_FIRST_DISABLED_QUERY_INDEX;
		}
		return FIRST_DISABLED_QUERY_INDEX;
	}

	private static Dataset jenaDatasetFor(Theme theme) {
		Dataset dataset = DatasetFactory.createTxnMem();
		boolean loaded = false;
		dataset.begin(ReadWrite.WRITE);
		try {
			org.apache.jena.rdf.model.Model jenaModel = dataset.getDefaultModel();
			ThemeDataSetGenerator.generate(theme, new AbstractRDFHandler() {
				@Override
				public void handleStatement(Statement statement) {
					jenaModel.add(resource(jenaModel, statement.getSubject()),
							jenaModel.createProperty(statement.getPredicate().stringValue()),
							rdfNode(jenaModel, statement.getObject()));
				}
			});
			dataset.commit();
			loaded = true;
			return dataset;
		} finally {
			dataset.end();
			if (!loaded) {
				dataset.close();
			}
		}
	}

	private static RDFNode rdfNode(org.apache.jena.rdf.model.Model model, Value value) {
		if (value instanceof Resource resource) {
			return resource(model, resource);
		}
		if (value instanceof Literal literal) {
			return literal(literal);
		}
		throw new IllegalArgumentException("Unsupported RDF4J value " + value);
	}

	private static org.apache.jena.rdf.model.Resource resource(org.apache.jena.rdf.model.Model model,
			Resource resource) {
		if (resource instanceof IRI iri) {
			return model.createResource(iri.stringValue());
		}
		if (resource instanceof BNode bNode) {
			return model.createResource(AnonId.create(bNode.getID()));
		}
		throw new IllegalArgumentException("Unsupported RDF4J resource " + resource);
	}

	private static RDFNode literal(Literal literal) {
		Optional<String> language = literal.getLanguage();
		if (language.isPresent()) {
			return ResourceFactory.createLangLiteral(literal.getLabel(), language.get());
		}
		RDFDatatype datatype = TypeMapper.getInstance().getSafeTypeByName(literal.getDatatype().stringValue());
		return ResourceFactory.createTypedLiteral(literal.getLabel(), datatype);
	}

	private record JenaResult(long rows, OptionalLong countValue) {
	}
}
